if c.AllowAllOrigins {
	headers.Set("Access-Control-Allow-Origin", "*")
} else {
	// Always set Vary headers
	// see https://github.com/rs/cors/issues/10,
	// https://github.com/rs/cors/commit/dbdca4d95feaa7511a46e6f1efb3b3aa505bc43f#commitcomment-12352001

	headers.Add("Vary", headerOrigin)
	headers.Add("Vary", "Access-Control-Request-Method")
	headers.Add("Vary", "Access-Control-Request-Headers")
}

if comment, ok := c.Comment(); ok && comment != "" {
	if c.multilineComment() {
		comment = strings.ReplaceAll(comment, "\n", "\\n")
		comment = strings.ReplaceAll(comment, `"`, `\"`)
		comment = strings.ReplaceAll(comment, "`", "'")
		comment = strings.ReplaceAll(comment, ":", " ")
		comment = strings.ReplaceAll(comment, ";", " ")
	}
	tag.Set(field.TagKeyGormComment, comment)
}

if s.Type == model.FOR {
	if len(s.splitList) != 5 {
		return fmt.Errorf("for range syntax error: %s", s.Value)
	}
	if s.SQLSlice.hasSameName(s.splitList[2]) {
		return fmt.Errorf("cannot use the same value name in different for loops")
	}
	s.ForRange.index = s.splitList[1]
	s.ForRange.value = s.splitList[2]
	s.ForRange.rangeList = s.splitList[4]
}

if specialTableName != "" {
	tableName = specialTableName
} else if en, ok := namer.(embeddedNamer); ok {
	tableName = en.Table
} else if tabler, ok := modelValue.Interface().(Tabler); ok {
	tableName = tabler.TableName()
} else if tabler, ok := modelValue.Interface().(TablerWithNamer); ok {
	tableName = tabler.TableName(namer)
} else {
	tableName = namer.TableName(modelType.Name())
}

for _, dbName := range stmt.Schema.DBNames {
	field := stmt.Schema.FieldsByDBName[dbName]
	if !field.IgnoreMigration {
		createTableSQL += "? ?"
		hasPrimaryKeyInDataType = hasPrimaryKeyInDataType || strings.Contains(strings.ToUpper(m.DataTypeOf(field)), "PRIMARY KEY")
		values = append(values, clause.Column{Name: dbName}, m.DB.Migrator().FullDataTypeOf(field))
		createTableSQL += ","
	}
}

for _, ref := range rel.References {
	fkNil[ref.ForeignKey.DBName] = nil

	if ref.OwnPrimaryKey && ref.PrimaryKey != nil {
		ownerPKNames = append(ownerPKNames, ref.PrimaryKey.DBName)
		primaryColumns = append(primaryColumns, clause.Column{Name: ref.PrimaryKey.DBName})
		foreignColumns = append(foreignColumns, clause.Column{Name: ref.ForeignKey.DBName})
	} else if !ref.OwnPrimaryKey && ref.PrimaryKey != nil {
		ownerFKNames = append(ownerFKNames, ref.ForeignKey.DBName)
		primaryColumns = append(primaryColumns, clause.Column{Name: ref.PrimaryKey.DBName})
	}
}

for idx, column := range columns {
	if reflectValue := reflect.Indirect(reflect.Indirect(reflect.ValueOf(values[idx]))); reflectValue.IsValid() {
		mapValue[column] = reflectValue.Interface()
		if valuer, ok := mapValue[column].(driver.Valuer); ok {
			mapValue[column], _ = valuer.Value()
		} else if b, ok := mapValue[column].(sql.RawBytes); ok {
			mapValue[column] = string(b)
		}
	} else {
		mapValue[column] = nil
	}
}

if stmt.Dest != nil {
	stmt.ReflectValue = reflect.ValueOf(stmt.Dest)
	for stmt.ReflectValue.Kind() == reflect.Ptr {
		if stmt.ReflectValue.IsNil() && stmt.ReflectValue.CanAddr() {
			stmt.ReflectValue.Set(reflect.New(stmt.ReflectValue.Type().Elem()))
		}

		stmt.ReflectValue = stmt.ReflectValue.Elem()
	}
	if !stmt.ReflectValue.IsValid() {
		db.AddError(ErrInvalidValue)
	}
}

if !db.AllowGlobalUpdate && db.Error == nil {
	where, withCondition := db.Statement.Clauses["WHERE"]
	if withCondition {
		if _, withSoftDelete := db.Statement.Clauses["soft_delete_enabled"]; withSoftDelete {
			whereClause, _ := where.Expression.(clause.Where)
			withCondition = len(whereClause.Exprs) > 1
		}
	}
	if !withCondition {
		db.AddError(gorm.ErrMissingWhereClause)
	}
	return
}

if v, ok := clause.Expression.(OrderBy); ok {
	for i := len(orderBy.Columns) - 1; i >= 0; i-- {
		if orderBy.Columns[i].Reorder {
			orderBy.Columns = orderBy.Columns[i:]
			clause.Expression = orderBy
			return
		}
	}

	copiedColumns := make([]OrderByColumn, len(v.Columns))
	copy(copiedColumns, v.Columns)
	orderBy.Columns = append(copiedColumns, orderBy.Columns...)
}

if db.Error == nil && !db.DryRun {
	result, err := db.Statement.ConnPool.ExecContext(db.Statement.Context, db.Statement.SQL.String(), db.Statement.Vars...)
	if err != nil {
		db.AddError(err)
		return
	}

	db.RowsAffected, _ = result.RowsAffected()

	if db.Statement.Result != nil {
		db.Statement.Result.Result = result
		db.Statement.Result.RowsAffected = db.RowsAffected
	}
}

switch data := v.(type) {
case **bool:
	if data != nil && *data != nil {
		field.ReflectValueOf(ctx, value).SetBool(**data)
	}
case bool:
	field.ReflectValueOf(ctx, value).SetBool(data)
case int64:
	field.ReflectValueOf(ctx, value).SetBool(data > 0)
case string:
	b, _ := strconv.ParseBool(data)
	field.ReflectValueOf(ctx, value).SetBool(b)
default:
	return fallbackSetter(ctx, value, v, field.Set)
}

if _, ok := relation.JoinTable.Relationships.Relations[relName]; !ok {
	relation.JoinTable.Relationships.Relations[relName] = &Relationship{
		Name:        relName,
		Type:        BelongsTo,
		Schema:      relation.JoinTable,
		FieldSchema: relation.Schema,
	}
} else {
	relation.JoinTable.Relationships.Relations[relName].References = []*Reference{}
}

if _, ok := relation.JoinTable.Relationships.Relations[relRefName]; !ok {
	relation.JoinTable.Relationships.Relations[relRefName] = &Relationship{
		Name:        relRefName,
		Type:        BelongsTo,
		Schema:      relation.JoinTable,
		FieldSchema: relation.FieldSchema,
	}
} else {
	relation.JoinTable.Relationships.Relations[relRefName].References = []*Reference{}
}

type ArticleModelValidator struct {
	Article struct {
		Title       string   `form:"title" json:"title" binding:"required,min=4"`
		Description string   `form:"description" json:"description" binding:"required,max=2048"`
		Body        string   `form:"body" json:"body" binding:"required,max=2048"`
		Tags        []string `form:"tagList" json:"tagList"`
	} `json:"article"`
	articleModel ArticleModel `json:"-"`
}

type UserModelValidator struct {
	User struct {
		Username string `form:"username" json:"username" binding:"required,min=4,max=255"`
		Email    string `form:"email" json:"email" binding:"required,email"`
		Password string `form:"password" json:"password" binding:"required,min=8,max=255"`
		Bio      string `form:"bio" json:"bio" binding:"max=1024"`
		Image    string `form:"image" json:"image" binding:"omitempty,url"`
	} `json:"user"`
	userModel UserModel `json:"-"`
}

for _, astSpec := range generalDeclaration.Specs {
	valueSpec, ok := astSpec.(*ast.ValueSpec)
	if !ok {
		continue
	}
	if len(valueSpec.Names) == 1 && len(valueSpec.Values) == 1 {
		lastValueSpec = valueSpec
	} else if len(valueSpec.Names) == 1 && len(valueSpec.Values) == 0 && valueSpec.Type == nil && lastValueSpec != nil {
		valueSpec.Type = lastValueSpec.Type
		valueSpec.Values = lastValueSpec.Values
	}
	pkg.AddConst(astFile, valueSpec)
}

if strings.EqualFold(matches[1], "all") {
	if operation.Responses.Default != nil {
		operation.Responses.Default.Headers[headerKey] = header
	}

	if operation.Responses.StatusCodeResponses != nil {
		for code, response := range operation.Responses.StatusCodeResponses {
			response.Headers[headerKey] = header
			operation.Responses.StatusCodeResponses[code] = response
		}
	}

	return nil
}

for _, codeStr := range strings.Split(matches[1], ",") {
	if strings.EqualFold(codeStr, defaultTag) {
		operation.DefaultResponse().WithDescription(description)

		continue
	}

	code, err := strconv.Atoi(codeStr)
	if err != nil {
		return fmt.Errorf("can not parse response comment \"%s\"", commentLine)
	}

	operation.AddResponse(code, spec.NewResponse().WithDescription(description))
}

for _, codeStr := range strings.Split(commentLine, ",") {
	if strings.EqualFold(codeStr, defaultTag) {
		_ = operation.DefaultResponse()

		continue
	}

	code, err := strconv.Atoi(codeStr)
	if err != nil {
		return fmt.Errorf("can not parse response comment \"%s\"", commentLine)
	}

	operation.AddResponse(code, spec.NewResponse().WithDescription(http.StatusText(code)))
}

if strings.HasSuffix(refType, ",") && strings.Contains(refType, "[") {
	// regexp may have broken generic syntax. find closing bracket and add it back
	allMatchesLenOffset := strings.Index(commentLine, refType) + len(refType)
	lostPartEndIdx := strings.Index(commentLine[allMatchesLenOffset:], "]")
	if lostPartEndIdx >= 0 {
		refType += commentLine[allMatchesLenOffset : allMatchesLenOffset+lostPartEndIdx+1]
	}
}
